use strict;
use warnings;

sub calculate {
    my ($a, $b, $op) = @_;

    if ($op eq "+") { return $a + $b; }
    elsif ($op eq "-") { return $a - $b; }
    elsif ($op eq "*") { return $a * $b; }
    elsif ($op eq "/") {
        if ($b == 0) {
            print "Hata: Sifira bolme!\n";
            return undef;
        }
        return $a / $b;
    }
    else {
        print "Gecersiz islem: $op\n";
        return undef;
    }
}

my ($x, $y) = (15, 4);

print "x = $x, y = $y\n";
print "x + y = " . calculate($x, $y, "+") . "\n";
print "x - y = " . calculate($x, $y, "-") . "\n";
print "x * y = " . calculate($x, $y, "*") . "\n";
print "x / y = " . calculate($x, $y, "/") . "\n";

print "\nSifira bolme testi:\n";
calculate(10, 0, "/");

